text:
flowchart TD
    classDef default fill:#ffffff,stroke:#888,stroke-width:2px,color:#000,rx:5px,ry:5px,padding:15px;
    classDef proc fill:#e6e6e6,stroke:#999,stroke-width:1px,color:#000,rx:5px,ry:5px,padding:15px;
    linkStyle default stroke:#757575,stroke-width:2px;

    subgraph part1["Pre-processing"]
        direction TB
        fastqc["&lt;b&gt;Rawdata Quality Control&lt;/b&gt;&lt;br/&gt;(fastqc)"]
        fastp["&lt;b&gt;Trim adpater and remove low qual reads&lt;/b&gt;&lt;br/&gt;(fastp)"]
    end
    subgraph part2["Alignment and BAM Processing"]
        direction TB
        bwa_align["&lt;b&gt;Mapping&lt;/b&gt;&lt;br/&gt;(bwa_align)"]
        sort_and_index["&lt;b&gt;Sort and index&lt;/b&gt;&lt;br/&gt;(sort_and_index)"]
        gatk_dedup["&lt;b&gt;Remove duplicates&lt;/b&gt;&lt;br/&gt;(gatk_dedup)"]
        gatk_realign["&lt;b&gt;Realign&lt;/b&gt;&lt;br/&gt;(gatk_realign)"]
        gatk_bqsr["&lt;b&gt;Base Quality Score Recalibration&lt;/b&gt;&lt;br/&gt;(gatk_bqsr)"]
        samtools_filtering["&lt;b&gt;Remove low qualtiy read&lt;/b&gt;&lt;br/&gt;(samtools_filtering)"]
    end
    subgraph part3["Analysis"]
        direction TB
        copykit["&lt;b&gt;Calculate CNV&lt;/b&gt;&lt;br/&gt;(copykit)"]
    end
    subgraph part4["QC"]
        direction TB
        gatk_qc_artifacts["&lt;b&gt;Artifacts&lt;/b&gt;&lt;br/&gt;(gatk_qc_artifacts)"]
        picard_qc_insert_size["&lt;b&gt;Insert Size&lt;/b&gt;&lt;br/&gt;(picard_qc_insert_size)"]
        gatk_qc_alignment_summary["&lt;b&gt;Alignment Summary&lt;/b&gt;&lt;br/&gt;(gatk_qc_alignment_summary)"]
        gatk_qc_wgs_metrics["&lt;b&gt;WGS Metrics&lt;/b&gt;&lt;br/&gt;(gatk_qc_wgs_metrics)"]
        mosdepth_coverage["&lt;b&gt;Coverage&lt;/b&gt;&lt;br/&gt;(mosdepth_coverage)"]
    end

    data_fastq["Fastq"] --&gt; fastqc
    data_fastq --&gt; fastp
    fastp --&gt; data_trimmed["Trimmed Fastq"]
    data_trimmed --&gt; bwa_align
    bwa_align --&gt; sort_and_index
    sort_and_index --&gt; gatk_dedup
    gatk_dedup --&gt; gatk_realign
    gatk_realign --&gt; gatk_bqsr
    gatk_bqsr --&gt; samtools_filtering
    samtools_filtering --&gt; data_analysis_bam1["Analysis Bam"]
    data_analysis_bam1 --&gt; copykit
    data_analysis_bam1 --&gt; gatk_qc_artifacts
    data_analysis_bam1 --&gt; picard_qc_insert_size
    data_analysis_bam1 --&gt; gatk_qc_alignment_summary
    data_analysis_bam1 --&gt; gatk_qc_wgs_metrics
    data_analysis_bam1 --&gt; mosdepth_coverage

        class fastqc proc;
        class fastp proc;
    style part1 fill:none,stroke:#b0bec5,stroke-width:2px,stroke-dasharray: 5 5;
        class bwa_align proc;
        class sort_and_index proc;
        class gatk_dedup proc;
        class gatk_realign proc;
        class gatk_bqsr proc;
        class samtools_filtering proc;
    style part2 fill:none,stroke:#b0bec5,stroke-width:2px,stroke-dasharray: 5 5;
        class copykit proc;
    style part3 fill:none,stroke:#b0bec5,stroke-width:2px,stroke-dasharray: 5 5;
        class gatk_qc_artifacts proc;
        class picard_qc_insert_size proc;
        class gatk_qc_alignment_summary proc;
        class gatk_qc_wgs_metrics proc;
        class mosdepth_coverage proc;
    style part4 fill:none,stroke:#b0bec5,stroke-width:2px,stroke-dasharray: 5 5;
